import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_name -> {(framework, pkg_id): resolved_version}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                lookup[key] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(after)

all_keys = sorted(set(bl.keys()) | set(al.keys()))

print('=== CHANGES ===')
changes = False
for k in all_keys:
    b = bl.get(k)
    a = al.get(k)
    if b != a:
        changes = True
        if b is None:
            print(f'  ADDED   {k[0]} / {k[1]} / {k[2]}: {a}')
        elif a is None:
            print(f'  REMOVED {k[0]} / {k[1]} / {k[2]}: was {b}')
        else:
            print(f'  CHANGED {k[0]} / {k[1]} / {k[2]}: {b} -> {a}')
if not changes:
    print('  (none)')

print()
print('=== UNCHANGED ===')
for k in all_keys:
    b = bl.get(k)
    a = al.get(k)
    if b == a:
        print(f'  {k[0]} / {k[1]} / {k[2]}: {a}')
"

