import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                lookup[key] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(after)
all_keys = sorted(set(bl.keys()) | set(al.keys()))

print('=== CHANGES ===')
changes = False
for k in all_keys:
    b = bl.get(k)
    a = al.get(k)
    if b != a:
        changes = True
        if b is None:
            print(f'  ADDED   {k[0]:20s} {k[1]:8s} {k[2]:45s} -> {a}')
        elif a is None:
            print(f'  REMOVED {k[0]:20s} {k[1]:8s} {k[2]:45s} was {b}')
        else:
            print(f'  CHANGED {k[0]:20s} {k[1]:8s} {k[2]:45s} {b} -> {a}')
if not changes:
    print('  (none)')

print()
print('=== UNCHANGED ===')
count = 0
for k in all_keys:
    b = bl.get(k)
    a = al.get(k)
    if b == a:
        count += 1
        print(f'  {k[0]:20s} {k[1]:8s} {k[2]:45s} {a}')
print(f'  ({count} entries)')
